{
  "success": true,
  "data": "{
  "database": "ercot_db",
  "query": "SELECT EXTRACT(YEAR FROM timestamp) AS yr, COUNT(*) AS n, MIN(timestamp) AS mn, MAX(timestamp) AS mx, AVG(lmp) AS avg_lmp FROM ercot_lmp WHERE zone_name='houston' AND zone_type='hub' AND is_day_ahead=true AND EXTRACT(YEAR FROM timestamp) IN (2023,2024) GROUP BY yr",
  "columns": [
    "yr",
    "n",
    "mn",
    "mx",
    "avg_lmp"
  ],
