  "data": "{
  "database": "ercot_db",
  "query": "WITH gas AS (\n  SELECT * FROM (VALUES\n    (2023,1,3.27),(2023,2,2.38),(2023,3,2.31),(2023,5,2.15),(2023,6,2.18),(2023,7,2.55),(2023,8,2.58),(2023,9,2.64),(2023,11,2.71),(2023,12,2.52),\n    (2024,1,3.18),(2024,2,1.72),(2024,3,1.49),(2024,5,2.12),(2024,6,2.54),(2024,7,2.07),(2024,8,1.99),(2024,9,2.28),(2024,11,2.12),(2024,12,3.01)\n  ) AS g(yr,mo,hh)\n),\nh AS (\n  SELECT EXTRACT(YEAR FROM timestamp)::int AS yr,\n         EXTRACT(MONTH FROM timestamp)::int AS mo,\n         lmp\n  FROM ercot_lmp\n  WHERE zone_name='houston' AND zone_type='hub' AND is_day_ahead=true\n    AND EXTRACT(YEAR FROM timestamp) IN (2023,2024)\n    AND EXTRACT(MONTH FROM timestamp) NOT IN (4,10)\n)\nSELECT h.yr,\n       SUM(CASE WHEN h.lmp > 6.5*g.hh THEN h.lmp - 6.5*g.hh ELSE 0 END) AS profit_usd,\n       COUNT(CASE WHEN h.lmp > 6.5*g.hh THEN 1 END) AS run_hours,\n       COUNT(*) AS avail_hours\nFROM h JOIN gas g ON h.yr=g.yr AND h.mo=g.mo\nGROUP BY h.yr ORDER BY h.yr",
  "columns": [
    "yr",
    "profit_usd",
    "run_hours",
    "avail_hours"
  ],
